const updates = $input.first().json.result || [];
if (updates.length === 0) return { json: { hasUpdates: false } };
const maxId = Math.max(...updates.map(u => u.update_id));
const messages = updates.map(u => ({
  update_id: u.update_id,
  message: u.message || u.edited_message || (u.callback_query || {}).message,
  type: u.callback_query ? 'callback' : (u.edited_message ? 'edited' : 'message'),
  callback_query: (u.callback_query || {}).data || null,
  maxUpdateId: maxId
})).filter(m => m.message);
return [{ json: { hasUpdates: true, messages, maxUpdateId } }];

